mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM report
    WHERE reporter_id = #{reporterId}
    AND target_member_id = #{targetMemberId}
    AND report_type = 'MEMBER'
    LIMIT 1
)

SELECT EXISTS (
    SELECT 1
    FROM report
    WHERE reporter_id = #{reporterId}
    AND room_id = #{roomId}
    AND report_type = 'ROOM'
    LIMIT 1
)

SELECT EXISTS (
    SELECT 1
    FROM report
    WHERE reporter_id = #{reporterId}
    AND chat_room_id = #{chatRoomId}
    AND report_type = 'CHAT'
    LIMIT 1
)

SELECT COUNT(*)
FROM report r
INNER JOIN members target ON target.member_id = r.target_member_id
INNER JOIN members reporter ON reporter.member_id = r.reporter_id


        AND r.status = #{status}


        AND r.report_type = #{reportType}


        AND (reporter.email LIKE CONCAT('%', #{reporter}, '%')
            OR reporter.name LIKE CONCAT('%', #{reporter}, '%'))


        AND (target.email LIKE CONCAT('%', #{target}, '%')
            OR target.name LIKE CONCAT('%', #{target}, '%'))


        AND DATE(r.report_created_at) >= #{from}


        AND DATE(r.report_created_at) <= #{to}

SELECT COUNT(*)
FROM report
WHERE status = #{status}

SELECT r.report_id AS reportId, r.room_id AS roomId, r.chat_room_id AS chatRoomId, r.target_member_id AS targetMemberId, target.email AS targetMemberEmail, target.name AS targetMemberName, r.reporter_id AS reporterId, reporter.email AS reporterEmail, reporter.name AS reporterName, r.report_type AS reportType, r.reason AS reason, r.status AS status, r.resolution_type AS resolutionType, r.resolution_message AS resolutionMessage, r.processed_by AS processedBy, processor.email AS processedByEmail, processor.name AS processedByName, r.processed_at AS processedAt, r.report_created_at AS reportCreatedAt FROM report r INNER JOIN members target ON target.member_id = r.target_member_id INNER JOIN members reporter ON reporter.member_id = r.reporter_id LEFT JOIN members processor ON processor.member_id = r.processed_by
AND r.status = #{status}
AND r.report_type = #{reportType}
AND (reporter.email LIKE CONCAT('%', #{reporter}, '%') OR reporter.name LIKE CONCAT('%', #{reporter}, '%'))
AND (target.email LIKE CONCAT('%', #{target}, '%') OR target.name LIKE CONCAT('%', #{target}, '%'))
AND DATE(r.report_created_at) >= #{from}
AND DATE(r.report_created_at) <= #{to}
ORDER BY r.report_created_at DESC, r.report_id DESC LIMIT #{limit} OFFSET #{offset}
